func TestSingularizeIdentifier(t *testing.T) {
	tests := map[string]struct {
		name        string
		inflections []Inflection
		want        string
	}{
		"empty identifier": {
			name: "",
			want: "",
		},
		"uncountable series": {
			name: "Series",
			want: "Series",
		},
		"canvas remains canvas": {
			name: "Canvas",
			want: "Canvas",
		},
		"irregular analyses": {
			name: "Analyses",
			want: "Analysis",
		},
		"camel case suffix": {
			name: "FactoryControls",
			want: "FactoryControl",
		},
		"custom inflection": {
			name: "UserSprocki",
			inflections: []Inflection{
				{Singular: "sprocket", Plural: "sprocki"},
			},
			want: "UserSprocket",
		},
		"custom inflection lower-case suffix": {
			name: "user_sprocki",
			inflections: []Inflection{
				{Singular: "sprocket", Plural: "sprocki"},
			},
			want: "user_sprocket",
		},
		"custom inflection upper-case suffix": {
			name: "USER_SPROCKI",
			inflections: []Inflection{
				{Singular: "sprocket", Plural: "sprocki"},
			},
			want: "USER_SPROCKET",
		},
		"custom inflection skips incomplete rule": {
			name: "UserSprocki",
			inflections: []Inflection{
				{Singular: "sprocket"},
				{Plural: "sprocki"},
			},
			want: "UserSprocki",
		},
		"custom inflection empty singular keeps default pluralizer": {
			name: "UserSprocki",
			inflections: []Inflection{
				{Singular: "", Plural: "sprocki"},
			},
			want: "UserSprocki",
		},
	}

	for name, tt := range tests {
		t.Run(name, func(t *testing.T) {
			if got := singularizeIdentifier(tt.name, tt.inflections); got != tt.want {
				t.Fatalf("singularizeIdentifier(%q) = %q, want %q", tt.name, got, tt.want)
			}
		})
	}
}

func TestLowerCamel(t *testing.T) {
	tests := map[string]string{
		"":          "",
		"UserID":    "userID",
		"ID":        "id",
		"IDs":       "ids",
		"URLValue":  "urlValue",
		"user_name": "userName",
	}

	for input, want := range tests {
