package cmd

import (
	"time"

	progressbar "github.com/schollz/progressbar/v3"
	"github.com/spf13/cobra"
)

// writeProgress writes a human-readable progress state to stderr.
func writeProgress(cmd *cobra.Command, format string, args ...any) error {
	bar := progressbar.NewOptions(
		1,
		progressbar.OptionSetWriter(cmd.ErrOrStderr()),
		progressbar.OptionSetVisibility(false),
	)
	_, err := progressbar.Bprintf(bar, format+"\n", args...)
	return err
}

// runWithProgress runs an operation while showing an indeterminate progress state.
func runWithProgress(cmd *cobra.Command, description string, run func() error) error {
	bar := progressbar.NewOptions(
		-1,
		progressbar.OptionSetWriter(cmd.ErrOrStderr()),
		progressbar.OptionSetDescription(" "+description),
		progressbar.OptionSpinnerType(14),
		progressbar.OptionThrottle(100*time.Millisecond),
		progressbar.OptionClearOnFinish(),
	)
	if err := bar.RenderBlank(); err != nil {
		return err
	}

	stop := make(chan struct{})
	progressErr := make(chan error, 1)
	go func() {
		ticker := time.NewTicker(100 * time.Millisecond)
		defer ticker.Stop()
		for {
			select {
			case <-ticker.C:
				if err := bar.Add(1); err != nil {
					progressErr <- err
					return
				}
			case <-stop:
				progressErr <- nil
				return
			}
		}
	}()

	runErr := run()
	close(stop)
	spinnerErr := <-progressErr
	finishErr := bar.Finish()
	if runErr != nil {
		return runErr
	}
	if spinnerErr != nil {
		return spinnerErr
	}
	return finishErr
}

